import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Output } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { BoardVariant } from '../../core/models/station.model';
import { DetectiveColor } from '../../core/models/player.model';
import { HumanRole } from '../../core/models/game-state.model';

export interface NewGameConfig {
  variant: BoardVariant;
  detectiveSetup: { color: DetectiveColor; startStation: number }[];
  misterXStart: number;
  humanRole: HumanRole;
  alwaysRevealMisterX: boolean;
}

const ALL_COLORS: DetectiveColor[] = ['blau', 'gelb', 'gruen', 'rot', 'schwarz'];

@Component({
  selector: 'app-setup',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './setup.component.html',
  styleUrl: './setup.component.scss'
})
export class SetupComponent {
  @Output() startGame = new EventEmitter<NewGameConfig>();

  variant: BoardVariant = 'klassisch';
  detectiveCount = 4;
  misterXStart = 1;
  humanRole: HumanRole = 'misterX';

  /** Entwicklungsmodus: Mister X immer sichtbar, zu Kontrollzwecken beim Testen der KI.
   *  Checkbox bewusst separat vom eigentlichen Regelwerk gehalten – vor "echten" Partien
   *  einfach deaktivieren bzw. dieses Feld später ganz entfernen. */
  alwaysRevealMisterX = true;

  /** Editierbare Startpositionen – Standard: zufällig, aber vor Spielstart frei anpassbar
   *  (z. B. anhand der physischen Startkarten aus der Originalspielschachtel). */
  slots: { color: DetectiveColor; startStation: number }[] = [];

  readonly maxStation = 199;

  constructor() {
    this.regenerateSlots();
  }

  get availableColors(): DetectiveColor[] {
    return ALL_COLORS;
  }

  onDetectiveCountChange(): void {
    this.regenerateSlots();
  }

  regenerateSlots(): void {
    const stations = this.pickDistinctRandomStations(this.detectiveCount + 1);
    this.misterXStart = stations[0];
    this.slots = ALL_COLORS.slice(0, this.detectiveCount).map((color, i) => ({
      color,
      startStation: stations[i + 1]
    }));
  }

  private pickDistinctRandomStations(count: number): number[] {
    const chosen = new Set<number>();
    while (chosen.size < count) {
      chosen.add(1 + Math.floor(Math.random() * this.maxStation));
    }
    return Array.from(chosen);
  }

  submit(): void {
    this.startGame.emit({
      variant: this.variant,
      detectiveSetup: this.slots,
      misterXStart: this.misterXStart,
      humanRole: this.humanRole,
      alwaysRevealMisterX: this.alwaysRevealMisterX
    });
  }
}

<div class="setup">
  <div class="setup__header">
    <span class="setup__brand">Scotland Yard</span>
    <button type="button" class="setup__rulebook-btn" (click)="toggleRulebook()">
      Spielanleitung
    </button>
  </div>

  <div class="setup__columns">
    <div class="column">
      <label class="field">
        Spielplan
        <select [(ngModel)]="variant">
          <option value="klassisch">Klassisch (1983)</option>
          <option value="modern">Modern (2000)</option>
        </select>
      </label>

      <label class="field">
        Ich spiele als
        <select [(ngModel)]="humanRole">
          <option value="misterX">Mister X (Detektive = KI)</option>
          <option value="detectives">Detektiv-Team (Mister X = KI)</option>
        </select>
      </label>

      <label class="field">
        Anzahl Detektive
        <select [(ngModel)]="detectiveCount" (ngModelChange)="onDetectiveCountChange()">
          <option [value]="2">2</option>
          <option [value]="3">3</option>
          <option [value]="4">4</option>
          <option [value]="5">5</option>
        </select>
      </label>

      <label class="checkbox-field">
        <input type="checkbox" [(ngModel)]="alwaysRevealMisterX" />
        Mister X immer sichtbar (Entwicklungsmodus – später deaktivieren)
      </label>
    </div>

    <div class="column">
      <div class="field-label">Startpositionen</div>
      <div class="slot">
        <span class="dot dot--mister-x"></span>
        Mister X – Start
        <input type="number" [(ngModel)]="misterXStart" min="1" [max]="maxStation" />
      </div>
      <div class="slot" *ngFor="let s of slots">
        <span class="dot" [class]="'dot--' + s.color"></span>
        Detektiv {{ s.color }} – Start
        <input type="number" [(ngModel)]="s.startStation" min="1" [max]="maxStation" />
      </div>
      <button type="button" class="secondary" (click)="regenerateSlots()">Neu auslosen</button>
      <p class="hint">
        Tipp: Trage hier die Nummern deiner physischen Startkarten ein, wenn du die
        Originalverteilung nutzen möchtest.
      </p>
    </div>
  </div>

  <button type="button" class="primary" (click)="submit()">Spiel starten</button>
</div>

<div class="rulebook-overlay" *ngIf="rulebookOpen" (click)="toggleRulebook()">
  <div class="rulebook-modal" (click)="$event.stopPropagation()">
    <div class="rulebook-modal__header">
      <span class="sy-plaque">Spielanleitung</span>
      <button type="button" class="rulebook-modal__close" (click)="toggleRulebook()">✕</button>
    </div>
    <div class="rulebook-modal__body">
      <p class="rulebook-modal__source">
        Wortwörtlicher Originaltext der Spielanleitung
        (Ravensburger Spiele Nr. 604 51427, © 1983 by Otto Maier Verlag Ravensburg).
      </p>
      <section *ngFor="let section of rulebookSections">
        <h3>{{ section.title }}</h3>
        <p *ngFor="let paragraph of section.paragraphs">{{ paragraph }}</p>
      </section>
    </div>
  </div>
</div>
